 89 | fn resolve_action_raw(args: &Value) -> Result<String> {
 90 |     if let Some(action) = args["action"].as_str() {
 91 |         return Ok(action.to_string());
 92 |     }
 93 | 
 94 |     if let Some(command) = args["command"].as_str() {
 95 |         if let Some(mapped) = action_from_command(command) {
 96 |             return Ok(mapped.to_string());
 97 |         }
 98 | 
 99 |         return Err(anyhow::anyhow!(
100 |             "Unsupported lsp command: {command}. Use action with one of: \
101 |              goToDefinition, findReferences, hover, documentSymbol, workspaceSymbol, \
102 |              goToImplementation, completion"
103 |         ));
104 |     }
105 | 
106 |     Err(anyhow::anyhow!("action is required"))
107 | }
