228 |     async fn execute(&self, args: Value) -> Result<ToolResult> {
229 |         let action_raw = resolve_action_raw(&args)?;
230 |         let action = LspOperation::parse(&action_raw)
231 |             .ok_or_else(|| anyhow::anyhow!("Unknown action: {}", action_raw))?;
232 | 
233 |         // Get the LSP manager and client
234 |         let manager = self.get_manager().await;
235 | 
236 |         // For workspace symbol search, we don't need a file
237 |         if action == LspOperation::WorkspaceSymbol {
238 |             let query = args["query"].as_str().unwrap_or("");
239 |             let language = get_file_path_arg(&args).and_then(detect_language_from_path);
240 | 
241 |             let client = if let Some(lang) = language {
242 |                 manager.get_client(lang).await?
243 |             } else {
244 |                 // Default to rust if we can't detect
245 |                 manager.get_client("rust").await?
246 |             };
247 | 
248 |             let result = client.workspace_symbols(query).await?;
249 |             return format_result(result);
250 |         }
251 | 
252 |         let file_path = get_file_path_arg(&args).ok_or_else(|| {
253 |             anyhow::anyhow!(
254 |                 "file_path is required (or use path) for action: {}",
255 |                 action_raw
256 |             )
257 |         })?;
258 |         let path = Path::new(file_path);
259 | 
260 |         let client = manager.get_client_for_file(path).await?;

260 |         let client = manager.get_client_for_file(path).await?;
261 | 
262 |         let line = args["line"].as_u64().map(|l| l as u32);
263 |         let column = args["column"].as_u64().map(|c| c as u32);
264 | 
265 |         if action.requires_position() && (line.is_none() || column.is_none()) {
266 |             return Ok(ToolResult::error(format!(
267 |                 "line and column are required for action: {}",
268 |                 action.canonical_name()
269 |             )));
270 |         }
271 | 
272 |         let result = match action {
273 |             LspOperation::GoToDefinition => {
274 |                 client
275 |                     .go_to_definition(path, line.unwrap(), column.unwrap())
276 |                     .await?
277 |             }
278 |             LspOperation::FindReferences => {
279 |                 let include_decl = args["include_declaration"].as_bool().unwrap_or(true);
280 |                 client
281 |                     .find_references(path, line.unwrap(), column.unwrap(), include_decl)
282 |                     .await?
283 |             }
284 |             LspOperation::Hover => client.hover(path, line.unwrap(), column.unwrap()).await?,
285 |             LspOperation::DocumentSymbol => client.document_symbols(path).await?,
286 |             LspOperation::GoToImplementation => {
287 |                 client
288 |                     .go_to_implementation(path, line.unwrap(), column.unwrap())
289 |                     .await?
290 |             }
291 |             LspOperation::Completion => {
292 |                 client
293 |                     .completion(path, line.unwrap(), column.unwrap())
294 |                     .await?
295 |             }
296 |             LspOperation::WorkspaceSymbol => {
297 |                 return Ok(ToolResult::error(format!(
298 |                     "Action {} is handled separately",
299 |                     action.canonical_name()
300 |                 )));
301 |             }
302 |         };
303 | 
304 |         format_result(result)
305 |     }
306 | }
