 56 |     /// Initialize the language server
 57 |     pub async fn initialize(&self) -> Result<()> {
 58 |         let root_uri = self.config.root_uri.clone();
 59 | 
 60 |         let params = InitializeParams {
 61 |             process_id: Some(std::process::id() as i64),
 62 |             client_info: ClientInfo {
 63 |                 name: "codetether".to_string(),
 64 |                 version: env!("CARGO_PKG_VERSION").to_string(),
 65 |             },
 66 |             locale: None,
 67 |             root_path: None,
 68 |             root_uri: root_uri.clone(),
 69 |             initialization_options: self.config.initialization_options.clone(),
 70 |             capabilities: ClientCapabilities::default(),
 71 |             trace: None,
 72 |             workspace_folders: None,
 73 |         };
 74 | 
 75 |         let response = self
 76 |             .transport
 77 |             .request("initialize", Some(serde_json::to_value(params)?))
 78 |             .await?;
 79 | 
 80 |         if let Some(error) = response.error {
 81 |             return Err(anyhow::anyhow!("LSP initialize error: {}", error.message));
 82 |         }
 83 | 
 84 |         if let Some(result) = response.result {
 85 |             let init_result: InitializeResult = serde_json::from_value(result)?;
 86 |             *self.server_capabilities.write().await = Some(init_result.capabilities);
 87 |             info!(
 88 |                 server_info = ?init_result.server_info,
 89 |                 "LSP server initialized"
 90 |             );
 91 |         }
 92 | 
 93 |         // Send initialized notification
 94 |         self.transport.notify("initialized", None).await?;
 95 |         self.transport.set_initialized(true);
 96 | 
 97 |         Ok(())
 98 |     }
