443 |         "typescript-language-server" => Some(&[
444 |             "npm",
445 |             "install",
446 |             "-g",
447 |             "typescript-language-server",
448 |             "typescript",
449 |         ]),
450 |         "pylsp" => Some(&["pip", "install", "--user", "python-lsp-server"]),
451 |         "gopls" => Some(&["go", "install", "golang.org/x/tools/gopls@latest"]),
