457 | /// Ensure a language server binary is available, installing it if possible.
458 | pub async fn ensure_server_installed(config: &LspConfig) -> Result<()> {
459 |     // Check if the binary is already on PATH.
460 |     if which::which(&config.command).is_ok() {
461 |         return Ok(());
462 |     }
463 | 
464 |     // rust-analyzer is commonly installed via rustup but may not be visible on PATH
465 |     // in the current process environment. Fall back to `rustup run <toolchain> rust-analyzer`.
466 |     if config.command == "rust-analyzer" {
467 |         let rustup_status = tokio::process::Command::new("rustup")
468 |             .args(["run", "stable", "rust-analyzer", "--version"])
469 |             .stdout(std::process::Stdio::null())
470 |             .stderr(std::process::Stdio::null())
471 |             .status()
472 |             .await;
473 | 
474 |         if let Ok(status) = rustup_status
475 |             && status.success()
476 |         {
477 |             return Ok(());
478 |         }
479 |     }
480 | 
481 |     let Some(install_args) = install_command_for(&config.command) else {
482 |         return Err(anyhow::anyhow!(
483 |             "Language server '{}' not found and no auto-install available. Install it manually.",
484 |             config.command,
485 |         ));
486 |     };
487 | 
488 |     info!(command = %config.command, "Language server not found, installing...");
489 | 
490 |     let output = tokio::process::Command::new(install_args[0])
491 |         .args(&install_args[1..])
492 |         .stdout(std::process::Stdio::piped())
493 |         .stderr(std::process::Stdio::piped())
494 |         .output()
495 |         .await?;
496 | 
497 |     if !output.status.success() {
498 |         let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
499 |         let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
500 |         return Err(anyhow::anyhow!(
501 |             "Failed to install '{}' (exit code {:?}). stdout: {} stderr: {}",
502 |             config.command,
503 |             output.status.code(),
504 |             stdout,
505 |             stderr,
506 |         ));
507 |     }
508 | 
509 |     // Verify installation succeeded
510 |     if which::which(&config.command).is_err() {
511 |         if config.command == "rust-analyzer" {
512 |             let rustup_status = tokio::process::Command::new("rustup")
513 |                 .args(["run", "stable", "rust-analyzer", "--version"])
514 |                 .stdout(std::process::Stdio::null())
515 |                 .stderr(std::process::Stdio::null())
516 |                 .status()
517 |                 .await;
518 |             if let Ok(status) = rustup_status
519 |                 && status.success()
520 |             {
521 |                 info!(command = %config.command, "Language server installed and available via rustup run stable");
522 |                 return Ok(());
523 |             }
524 |         }
525 |         warn!(command = %config.command, "Install succeeded but binary still not found on PATH");
526 |     } else {
527 |         info!(command = %config.command, "Language server installed successfully");
528 |     }
529 | 
530 |     Ok(())
531 | }
