535 |     let ext = path.rsplit('.').next()?;
536 |     match ext {
537 |         "rs" => Some("rust"),
538 |         "ts" | "tsx" => Some("typescript"),
539 |         "js" | "jsx" => Some("javascript"),
540 |         "py" => Some("python"),
541 |         "go" => Some("go"),
542 |         "c" => Some("c"),
543 |         "cpp" | "cc" | "cxx" => Some("cpp"),
544 |         "h" => Some("c"),
545 |         "hpp" => Some("cpp"),
546 |         _ => None,
547 |     }
548 | }

