  1 | //! LSP transport layer - stdio implementation with Content-Length framing
  2 | //!
  3 | //! LSP uses a special framing format with Content-Length headers:
  4 | //! ```text
  5 | //! Content-Length: 123\r\n
  6 | //! \r\n
  7 | //! <JSON payload>
  8 | //! ```
  9 | 
 10 | use super::types::{JsonRpcNotification, JsonRpcRequest, JsonRpcResponse};
 11 | use anyhow::{Context, Result};
 12 | use std::sync::Arc;
 13 | use std::sync::atomic::{AtomicI64, Ordering};
 14 | use tokio::io::{AsyncBufReadExt, AsyncReadExt, AsyncWriteExt, BufReader};
 15 | use tokio::process::{Child, Command};
 16 | use tokio::sync::{RwLock, mpsc, oneshot};
 17 | use tracing::{debug, error, trace, warn};
 18 | 
 19 | /// LSP Transport for communicating with language servers
 20 | pub struct LspTransport {
 21 |     /// The child process (kept alive for the transport lifetime)
 22 |     _child: Child,
 23 |     /// Channel for sending messages
 24 |     tx: mpsc::Sender<String>,
 25 |     /// Pending requests waiting for responses
 26 |     pending: Arc<RwLock<std::collections::HashMap<i64, oneshot::Sender<JsonRpcResponse>>>>,
 27 |     /// Request ID counter
 28 |     request_id: AtomicI64,
 29 |     /// Whether the server is initialized
 30 |     initialized: std::sync::atomic::AtomicBool,
 31 |     /// Per-request timeout in milliseconds.
 32 |     timeout_ms: u64,
 33 |     /// Recent stderr lines from the language server for diagnostics.
 34 |     recent_stderr: Arc<RwLock<Vec<String>>>,
 35 |     /// Server command for diagnostics.
 36 |     command: String,
 37 | }
 38 | 
 39 | impl LspTransport {
 40 |     /// Spawn a language server and create a transport
 41 |     pub async fn spawn(command: &str, args: &[String], timeout_ms: u64) -> Result<Self> {
 42 |         let mut child = Command::new(command)
 43 |             .args(args)
 44 |             .stdin(std::process::Stdio::piped())
 45 |             .stdout(std::process::Stdio::piped())
 46 |             .stderr(std::process::Stdio::piped())
 47 |             .spawn()
 48 |             .with_context(|| format!("Failed to spawn language server '{command}'"))?;
 49 | 
 50 |         let stdout = child
 51 |             .stdout
 52 |             .take()
 53 |             .ok_or_else(|| anyhow::anyhow!("No stdout"))?;
 54 |         let stderr = child
 55 |             .stderr
 56 |             .take()
 57 |             .ok_or_else(|| anyhow::anyhow!("No stderr"))?;
 58 |         let mut stdin = child
 59 |             .stdin
 60 |             .take()
 61 |             .ok_or_else(|| anyhow::anyhow!("No stdin"))?;
 62 | 
 63 |         let (write_tx, mut write_rx) = mpsc::channel::<String>(100);
 64 |         let pending: Arc<RwLock<std::collections::HashMap<i64, oneshot::Sender<JsonRpcResponse>>>> =
 65 |             Arc::new(RwLock::new(std::collections::HashMap::new()));
 66 |         let recent_stderr = Arc::new(RwLock::new(Vec::new()));
 67 | 
 68 |         // Writer task - sends messages with Content-Length framing
 69 |         let pending_clone = Arc::clone(&pending);
 70 |         tokio::spawn(async move {
 71 |             while let Some(msg) = write_rx.recv().await {
 72 |                 let content_length = msg.len();
 73 |                 let header = format!("Content-Length: {}\r\n\r\n", content_length);
 74 |                 trace!("LSP TX header: {}", header.trim());
 75 |                 trace!("LSP TX body: {}", msg);
 76 | 
 77 |                 if let Err(e) = stdin.write_all(header.as_bytes()).await {
 78 |                     error!("Failed to write header to LSP server: {}", e);
 79 |                     break;
 80 |                 }
 81 |                 if let Err(e) = stdin.write_all(msg.as_bytes()).await {
 82 |                     error!("Failed to write body to LSP server: {}", e);
 83 |                     break;
 84 |                 }
 85 |                 if let Err(e) = stdin.flush().await {
 86 |                     error!("Failed to flush LSP server stdin: {}", e);
 87 |                     break;
 88 |                 }
 89 |             }
 90 |             // Clear pending requests on shutdown
 91 |             pending_clone.write().await.clear();
 92 |         });
 93 | 
 94 |         // Stderr task - capture recent diagnostics from the language server.
 95 |         let recent_stderr_clone = Arc::clone(&recent_stderr);
 96 |         let stderr_command = command.to_string();
 97 |         tokio::spawn(async move {
 98 |             let mut reader = BufReader::new(stderr);
 99 |             let mut line = String::new();
100 |             loop {
101 |                 line.clear();
102 |                 match reader.read_line(&mut line).await {
103 |                     Ok(0) => return,
104 |                     Ok(_) => {
105 |                         let trimmed = line.trim().to_string();
106 |                         if trimmed.is_empty() {
107 |                             continue;
108 |                         }
109 |                         warn!(command = %stderr_command, stderr = %trimmed, "Language server stderr");
110 |                         let mut guard = recent_stderr_clone.write().await;
111 |                         guard.push(trimmed);
112 |                         if guard.len() > 20 {
113 |                             let excess = guard.len() - 20;
114 |                             guard.drain(0..excess);
115 |                         }
116 |                     }
117 |                     Err(e) => {
118 |                         warn!(command = %stderr_command, error = %e, "Failed reading language server stderr");
119 |                         return;
120 |                     }
121 |                 }
122 |             }
123 |         });
124 | 
125 |         // Reader task - parses Content-Length framed responses
126 |         let pending_clone = Arc::clone(&pending);
127 |         tokio::spawn(async move {
128 |             let mut reader = BufReader::new(stdout);
129 |             let mut header_buf = String::new();
130 | 
131 |             loop {
132 |                 // Read headers until empty line
133 |                 header_buf.clear();
134 |                 let mut content_length: Option<usize> = None;
135 | 
136 |                 loop {
137 |                     header_buf.clear();
138 |                     match reader.read_line(&mut header_buf).await {
139 |                         Ok(0) => {
140 |                             debug!("LSP server closed connection");
141 |                             return;
142 |                         }
143 |                         Ok(_) => {
144 |                             let line = header_buf.trim();
145 |                             if line.is_empty() {
146 |                                 break; // End of headers
147 |                             }
148 |                             if let Some(stripped) = line.strip_prefix("Content-Length:")
149 |                                 && let Ok(len) = stripped.trim().parse::<usize>()
150 |                             {
151 |                                 content_length = Some(len);
152 |                             }
153 |                             // Ignore other headers (Content-Type, etc.)
154 |                         }
155 |                         Err(e) => {
156 |                             error!("Failed to read header from LSP server: {}", e);
157 |                             return;
158 |                         }
159 |                     }
160 |                 }
161 | 
162 |                 let Some(len) = content_length else {
163 |                     warn!("LSP message missing Content-Length header");
164 |                     continue;
165 |                 };
166 | 
167 |                 // Read the body
168 |                 let mut body_buf = vec![0u8; len];
169 |                 match reader.read_exact(&mut body_buf).await {
170 |                     Ok(_) => {
171 |                         let body = String::from_utf8_lossy(&body_buf);
172 |                         trace!("LSP RX: {}", body);
173 | 
174 |                         // Parse as JSON-RPC response
175 |                         match serde_json::from_str::<JsonRpcResponse>(&body) {
176 |                             Ok(response) => {
177 |                                 // Find and complete the pending request
178 |                                 let mut pending_guard = pending_clone.write().await;
179 |                                 if let Some(tx) = pending_guard.remove(&response.id) {
180 |                                     let id = response.id;
181 |                                     if tx.send(response).is_err() {
182 |                                         warn!("Request {} receiver dropped", id);
183 |                                     }
184 |                                 } else {
185 |                                     // Could be a response to a notification or unknown request
186 |                                     debug!("Received response for unknown request {}", response.id);
187 |                                 }
188 |                             }
189 |                             Err(e) => {
190 |                                 // Might be a notification (no id) or malformed
191 |                                 debug!("Failed to parse LSP response: {} - body: {}", e, body);
192 |                             }
193 |                         }
194 |                     }
195 |                     Err(e) => {
196 |                         error!("Failed to read LSP message body: {}", e);
197 |                         return;
198 |                     }
199 |                 }
200 |             }
201 |         });
202 | 
203 |         Ok(Self {
204 |             _child: child,
205 |             tx: write_tx,
206 |             pending,
207 |             request_id: AtomicI64::new(1),
208 |             initialized: std::sync::atomic::AtomicBool::new(false),
209 |             timeout_ms,
210 |             recent_stderr,
211 |             command: command.to_string(),
212 |         })
213 |     }
214 | 
215 |     /// Send a request and wait for response
216 |     pub async fn request(
217 |         &self,
218 |         method: &str,
219 |         params: Option<serde_json::Value>,
220 |     ) -> Result<JsonRpcResponse> {
221 |         let id = self.request_id.fetch_add(1, Ordering::SeqCst);
222 |         let request = JsonRpcRequest::new(id, method, params);
223 | 
224 |         let (tx, rx) = oneshot::channel();
225 |         self.pending.write().await.insert(id, tx);
226 | 
227 |         let json = serde_json::to_string(&request)?;
228 |         self.tx.send(json).await?;
229 | 
230 |         // Wait for response with timeout
231 |         let response = tokio::time::timeout(std::time::Duration::from_millis(self.timeout_ms), rx)
232 |             .await
233 |             .map_err(|_| {
234 |                 let stderr_summary = self.stderr_summary();
235 |                 anyhow::anyhow!(
236 |                     "LSP request timeout for method: {} (server: {}, timeout: {}ms{})",
237 |                     method,
238 |                     self.command,
239 |                     self.timeout_ms,
240 |                     stderr_summary
241 |                         .as_deref()
242 |                         .map(|summary| format!(", recent stderr: {summary}"))
243 |                         .unwrap_or_default()
244 |                 )
245 |             })?
246 |             .map_err(|_| anyhow::anyhow!("LSP response channel closed"))?;
247 | 
248 |         Ok(response)
249 |     }
250 | 
251 |     fn stderr_summary(&self) -> Option<String> {
252 |         self.recent_stderr.try_read().ok().and_then(|lines| {
253 |             if lines.is_empty() {
254 |                 None
255 |             } else {
256 |                 Some(lines.join(" | "))
257 |             }
258 |         })
259 |     }
260 | 
261 |     /// Send a notification (no response expected)
262 |     pub async fn notify(&self, method: &str, params: Option<serde_json::Value>) -> Result<()> {
263 |         let notification = JsonRpcNotification::new(method, params);
264 |         let json = serde_json::to_string(&notification)?;
265 |         self.tx.send(json).await?;
266 |         Ok(())
267 |     }
268 | 
269 |     /// Check if the server is initialized
270 |     pub fn is_initialized(&self) -> bool {
271 |         self.initialized.load(std::sync::atomic::Ordering::SeqCst)
272 |     }
273 | 
274 |     /// Mark the server as initialized
275 |     pub fn set_initialized(&self, value: bool) {
276 |         self.initialized
277 |             .store(value, std::sync::atomic::Ordering::SeqCst);
278 |     }
279 | }
280 | 
281 | impl Drop for LspTransport {
282 |     fn drop(&mut self) {
283 |         if self.is_initialized() {
284 |             tracing::debug!("LspTransport dropped while still initialized");
285 |         }
286 |     }
287 | }

