437 | /// Parse a location response (definition, references, implementation)
438 | fn parse_location_response(response: JsonRpcResponse, _operation: &str) -> Result<LspActionResult> {
439 |     if let Some(error) = response.error {
440 |         return Ok(LspActionResult::Error {
441 |             message: error.message,
442 |         });
443 |     }
444 | 
445 |     let Some(result) = response.result else {
446 |         return Ok(LspActionResult::Definition { locations: vec![] });
447 |     };
448 | 
449 |     // Try to parse as a single location
450 |     if let Ok(loc) = serde_json::from_value::<lsp_types::Location>(result.clone()) {
451 |         return Ok(LspActionResult::Definition {
452 |             locations: vec![LocationInfo::from(loc)],
453 |         });
454 |     }
455 | 
456 |     // Try to parse as an array of locations
457 |     if let Ok(locs) = serde_json::from_value::<Vec<lsp_types::Location>>(result.clone()) {
458 |         return Ok(LspActionResult::Definition {
459 |             locations: locs.into_iter().map(LocationInfo::from).collect(),
460 |         });
461 |     }
462 | 
463 |     // Try to parse as LocationLink array
464 |     if let Ok(links) = serde_json::from_value::<Vec<lsp_types::LocationLink>>(result) {
465 |         return Ok(LspActionResult::Definition {
466 |             locations: links
467 |                 .into_iter()
468 |                 .map(|link| LocationInfo {
469 |                     uri: link.target_uri.to_string(),
470 |                     range: RangeInfo::from(link.target_selection_range),
471 |                 })
472 |                 .collect(),
473 |         });
474 |     }
475 | 
476 |     Ok(LspActionResult::Definition { locations: vec![] })
477 | }
