479 | /// Parse a hover response
480 | fn parse_hover_response(response: JsonRpcResponse) -> Result<LspActionResult> {
481 |     if let Some(error) = response.error {
482 |         return Ok(LspActionResult::Error {
483 |             message: error.message,
484 |         });
485 |     }
486 | 
487 |     let Some(result) = response.result else {
488 |         return Ok(LspActionResult::Hover {
489 |             contents: String::new(),
490 |             range: None,
491 |         });
492 |     };
493 | 
494 |     if result.is_null() {
495 |         return Ok(LspActionResult::Hover {
496 |             contents: "No hover information available".to_string(),
497 |             range: None,
498 |         });
499 |     }
500 | 
501 |     let hover: lsp_types::Hover = serde_json::from_value(result)?;
502 | 
503 |     let contents = match hover.contents {
504 |         lsp_types::HoverContents::Scalar(markup) => match markup {
505 |             lsp_types::MarkedString::String(s) => s,
506 |             lsp_types::MarkedString::LanguageString(ls) => ls.value,
507 |         },
508 |         lsp_types::HoverContents::Array(markups) => markups
509 |             .into_iter()
510 |             .map(|m| match m {
511 |                 lsp_types::MarkedString::String(s) => s,
512 |                 lsp_types::MarkedString::LanguageString(ls) => ls.value,
513 |             })
514 |             .collect::<Vec<_>>()
515 |             .join("\n\n"),
516 |         lsp_types::HoverContents::Markup(markup) => markup.value,
517 |     };
518 | 
519 |     Ok(LspActionResult::Hover {
520 |         contents,
521 |         range: hover.range.map(RangeInfo::from),
522 |     })
523 | }
