525 | /// Parse a document symbols response
526 | fn parse_document_symbols_response(response: JsonRpcResponse) -> Result<LspActionResult> {
527 |     if let Some(error) = response.error {
528 |         return Ok(LspActionResult::Error {
529 |             message: error.message,
530 |         });
531 |     }
532 | 
533 |     let Some(result) = response.result else {
534 |         return Ok(LspActionResult::DocumentSymbols { symbols: vec![] });
535 |     };
