 17 | #[derive(Debug, Clone, Copy, PartialEq, Eq)]
 18 | enum LspOperation {
 19 |     GoToDefinition,
 20 |     FindReferences,
 21 |     Hover,
 22 |     DocumentSymbol,
 23 |     WorkspaceSymbol,
 24 |     GoToImplementation,
 25 |     Completion,
 26 | }
 27 | 
 28 | impl LspOperation {
 29 |     fn parse(action: &str) -> Option<Self> {
 30 |         match action {
 31 |             "goToDefinition" | "go-to-definition" | "go_to_definition" => {
 32 |                 Some(Self::GoToDefinition)
 33 |             }
 34 |             "findReferences" | "find-references" | "find_references" => Some(Self::FindReferences),
 35 |             "hover" => Some(Self::Hover),
 36 |             "documentSymbol" | "document-symbol" | "document_symbol" => Some(Self::DocumentSymbol),
 37 |             "workspaceSymbol" | "workspace-symbol" | "workspace_symbol" => {
 38 |                 Some(Self::WorkspaceSymbol)
 39 |             }
 40 |             "goToImplementation" | "go-to-implementation" | "go_to_implementation" => {
 41 |                 Some(Self::GoToImplementation)
 42 |             }
 43 |             "completion" => Some(Self::Completion),
 44 |             _ => None,
 45 |         }
 46 |     }
 47 | 
 48 |     fn requires_position(self) -> bool {
 49 |         match self {
 50 |             Self::GoToDefinition
 51 |             | Self::FindReferences
 52 |             | Self::Hover
 53 |             | Self::GoToImplementation
 54 |             | Self::Completion => true,
 55 |             Self::DocumentSymbol | Self::WorkspaceSymbol => false,
 56 |         }
 57 |     }
 58 | 
 59 |     fn canonical_name(self) -> &'static str {
 60 |         match self {
 61 |             Self::GoToDefinition => "goToDefinition",
 62 |             Self::FindReferences => "findReferences",
 63 |             Self::Hover => "hover",
 64 |             Self::DocumentSymbol => "documentSymbol",
 65 |             Self::WorkspaceSymbol => "workspaceSymbol",
 66 |             Self::GoToImplementation => "goToImplementation",
 67 |             Self::Completion => "completion",
 68 |         }
 69 |     }
 70 | }
