 72 | fn get_file_path_arg(args: &Value) -> Option<&str> {
 73 |     args["file_path"].as_str().or_else(|| args["path"].as_str())
 74 | }
 75 | 
 76 | fn action_from_command(command: &str) -> Option<&'static str> {
 77 |     match command {
 78 |         "textDocument/definition" => Some("goToDefinition"),
 79 |         "textDocument/references" => Some("findReferences"),
 80 |         "textDocument/hover" => Some("hover"),
 81 |         "textDocument/documentSymbol" => Some("documentSymbol"),
 82 |         "workspace/symbol" => Some("workspaceSymbol"),
 83 |         "textDocument/implementation" => Some("goToImplementation"),
 84 |         "textDocument/completion" => Some("completion"),
 85 |         _ => None,
 86 |     }
 87 | }
