109 | /// LSP Tool for performing Language Server Protocol operations
110 | pub struct LspTool {
111 |     root_uri: Option<String>,
112 | }
113 | 
114 | impl LspTool {
115 |     pub fn new() -> Self {
116 |         Self { root_uri: None }
117 |     }
