126 |     /// Shutdown all LSP clients, releasing resources.
127 |     #[allow(dead_code)]
128 |     pub async fn shutdown_all(&self) {
129 |         let cell = LSP_MANAGER.get_or_init(|| Arc::new(RwLock::new(None)));
130 |         let guard = cell.read().await;
131 |         if let Some(manager) = guard.as_ref() {
132 |             manager.shutdown_all().await;
133 |         }
134 |     }
135 | 
136 |     /// Get or initialize the LSP manager
137 |     async fn get_manager(&self) -> Arc<LspManager> {
138 |         let cell = LSP_MANAGER.get_or_init(|| Arc::new(RwLock::new(None)));
139 |         let mut guard = cell.write().await;
140 | 
141 |         if guard.is_none() {
142 |             *guard = Some(Arc::new(LspManager::new(self.root_uri.clone())));
143 |         }
144 | 
145 |         Arc::clone(guard.as_ref().unwrap())
146 |     }
147 | }
