155 | #[async_trait]
156 | impl Tool for LspTool {
157 |     fn id(&self) -> &str {
158 |         "lsp"
159 |     }
160 | 
161 |     fn name(&self) -> &str {
162 |         "LSP Tool"
163 |     }
164 | 
165 |     fn description(&self) -> &str {
166 |         "Perform Language Server Protocol (LSP) operations such as go-to-definition, find-references, hover, document-symbol, workspace-symbol, and more. This tool enables AI agents to query language servers for code intelligence features. Supports rust-analyzer, typescript-language-server, pylsp, gopls, and clangd."
167 |     }
