169 |     fn parameters(&self) -> Value {
170 |         json!({
171 |             "type": "object",
172 |             "properties": {
173 |                 "action": {
174 |                     "type": "string",
175 |                     "description": "The LSP operation to perform",
176 |                     "enum": [
177 |                         "goToDefinition",
178 |                         "go-to-definition",
179 |                         "go_to_definition",
180 |                         "findReferences",
181 |                         "find-references",
182 |                         "find_references",
183 |                         "hover",
184 |                         "documentSymbol",
185 |                         "document-symbol",
186 |                         "document_symbol",
187 |                         "workspaceSymbol",
188 |                         "workspace-symbol",
189 |                         "workspace_symbol",
190 |                         "goToImplementation",
191 |                         "go-to-implementation",
192 |                         "go_to_implementation",
193 |                         "completion"
194 |                     ]
195 |                 },
196 |                 "file_path": {
197 |                     "type": "string",
198 |                     "description": "The absolute or relative path to the file"
199 |                 },
200 |                 "path": {
201 |                     "type": "string",
202 |                     "description": "Alias for file_path"
203 |                 },
204 |                 "line": {
205 |                     "type": "integer",
206 |                     "description": "The line number (1-based, as shown in editors)",
207 |                     "minimum": 1
208 |                 },
209 |                 "column": {
210 |                     "type": "integer",
211 |                     "description": "The character offset/column (1-based, as shown in editors)",
212 |                     "minimum": 1
213 |                 },
214 |                 "query": {
215 |                     "type": "string",
216 |                     "description": "Search query for workspaceSymbol action"
217 |                 },
218 |                 "include_declaration": {
219 |                     "type": "boolean",
220 |                     "description": "For findReferences: include the declaration in results",
221 |                     "default": true
222 |                 }
223 |             },
224 |             "required": ["action"]
225 |         })
