308 | /// Format LSP result as tool output
309 | fn format_result(result: LspActionResult) -> Result<ToolResult> {
310 |     let output = match result {
311 |         LspActionResult::Definition { locations } => {
312 |             if locations.is_empty() {
313 |                 "No definition found".to_string()
314 |             } else {
315 |                 let mut out = format!("Found {} definition(s):\n\n", locations.len());
316 |                 for loc in locations {
317 |                     let uri = loc.uri;
318 |                     let range = loc.range;
319 |                     out.push_str(&format!(
320 |                         "  {}:{}:{}\n",
321 |                         uri.trim_start_matches("file://"),
322 |                         range.start.line + 1,
323 |                         range.start.character + 1
324 |                     ));
325 |                 }
326 |                 out
327 |             }
328 |         }
329 |         LspActionResult::References { locations } => {
330 |             if locations.is_empty() {
331 |                 "No references found".to_string()
332 |             } else {
333 |                 let mut out = format!("Found {} reference(s):\n\n", locations.len());
334 |                 for loc in locations {
335 |                     let uri = loc.uri;
336 |                     let range = loc.range;
337 |                     out.push_str(&format!(
338 |                         "  {}:{}:{}\n",
339 |                         uri.trim_start_matches("file://"),
340 |                         range.start.line + 1,
341 |                         range.start.character + 1
342 |                     ));
343 |                 }
344 |                 out
345 |             }
346 |         }
347 |         LspActionResult::Hover { contents, range } => {
348 |             let mut out = "Hover information:\n\n".to_string();
349 |             out.push_str(&contents);
350 |             if let Some(r) = range {
351 |                 out.push_str(&format!(
352 |                     "\n\nRange: line {}-{}, col {}-{}",
353 |                     r.start.line + 1,
354 |                     r.end.line + 1,
355 |                     r.start.character + 1,
356 |                     r.end.character + 1
357 |                 ));
358 |             }
359 |             out
360 |         }

360 |         }
361 |         LspActionResult::DocumentSymbols { symbols } => {
362 |             if symbols.is_empty() {
363 |                 "No symbols found in document".to_string()
364 |             } else {
365 |                 let mut out = format!("Document symbols ({}):\n\n", symbols.len());
366 |                 for sym in symbols {
367 |                     out.push_str(&format!("  {} [{}]", sym.name, sym.kind));
368 |                     if let Some(detail) = sym.detail {
369 |                         out.push_str(&format!(" - {}", detail));
370 |                     }
371 |                     out.push('\n');
372 |                 }
373 |                 out
374 |             }
375 |         }
376 |         LspActionResult::WorkspaceSymbols { symbols } => {
377 |             if symbols.is_empty() {
378 |                 "No symbols found matching query".to_string()
379 |             } else {
380 |                 let mut out = format!("Workspace symbols ({}):\n\n", symbols.len());
381 |                 for sym in symbols {
382 |                     out.push_str(&format!("  {} [{}]", sym.name, sym.kind));
383 |                     if let Some(uri) = sym.uri {
384 |                         out.push_str(&format!(" - {}", uri.trim_start_matches("file://")));
385 |                     }
386 |                     out.push('\n');
387 |                 }
388 |                 out
389 |             }
390 |         }
391 |         LspActionResult::Implementation { locations } => {
392 |             if locations.is_empty() {
393 |                 "No implementations found".to_string()
394 |             } else {
395 |                 let mut out = format!("Found {} implementation(s):\n\n", locations.len());
396 |                 for loc in locations {
397 |                     let uri = loc.uri;
398 |                     let range = loc.range;
399 |                     out.push_str(&format!(
400 |                         "  {}:{}:{}\n",
401 |                         uri.trim_start_matches("file://"),
402 |                         range.start.line + 1,
403 |                         range.start.character + 1
404 |                     ));
405 |                 }
406 |                 out
407 |             }
408 |         }
409 |         LspActionResult::Completion { items } => {
410 |             if items.is_empty() {
411 |                 "No completions available".to_string()
412 |             } else {
413 |                 let mut out = format!("Completions ({}):\n\n", items.len());
414 |                 for item in items {
415 |                     out.push_str(&format!("  {}", item.label));
416 |                     if let Some(kind) = item.kind {
417 |                         out.push_str(&format!(" [{}]", kind));
418 |                     }
419 |                     if let Some(detail) = item.detail {
420 |                         out.push_str(&format!(" - {}", detail));
421 |                     }
422 |                     out.push('\n');
423 |                 }
424 |                 out
425 |             }
426 |         }
427 |         LspActionResult::Error { message } => {
428 |             return Ok(ToolResult::error(message));
429 |         }
430 |     };
431 | 
432 |     Ok(ToolResult::success(output))
433 | }
