 101 | fn tool_call_markup_re() -> &'static Regex {
 102 |     static TOOL_CALL_RE: OnceLock<Regex> = OnceLock::new();
 103 |     TOOL_CALL_RE.get_or_init(|| {
 104 |         Regex::new(r"(?s)<tool_call>\s*(?:```(?:json)?\s*)?(\{.*?\})(?:\s*```)?\s*</tool_call>")
 105 |             .expect("tool_call regex must compile")
 106 |     })
 107 | }
