 109 | fn extract_markup_tool_calls(text: &str) -> (String, Vec<(String, String)>) {
 110 |     let mut calls = Vec::new();
 111 |     let re = tool_call_markup_re();
 112 | 
 113 |     for capture in re.captures_iter(text) {
 114 |         let Some(block) = capture.get(1).map(|m| m.as_str()) else {
 115 |             continue;
 116 |         };
 117 |         let Ok(payload) = serde_json::from_str::<Value>(block) else {
 118 |             continue;
 119 |         };
 120 |         let Some(name) = payload.get("name").and_then(Value::as_str) else {
 121 |             continue;
 122 |         };
 123 |         let arguments = payload
 124 |             .get("arguments")
 125 |             .map(|v| serde_json::to_string(v).unwrap_or_else(|_| "{}".to_string()))
 126 |             .unwrap_or_else(|| "{}".to_string());
 127 |         calls.push((name.to_string(), arguments));
 128 |     }
 129 | 
 130 |     let cleaned = re.replace_all(text, "").into_owned();
 131 |     (cleaned, calls)
 132 | }
