 134 | fn normalize_textual_tool_calls(
 135 |     mut response: CompletionResponse,
 136 |     tools: &[ToolDefinition],
 137 | ) -> CompletionResponse {
 138 |     if response
 139 |         .message
 140 |         .content
 141 |         .iter()
 142 |         .any(|p| matches!(p, ContentPart::ToolCall { .. }))
 143 |     {
 144 |         return response;
 145 |     }
 146 | 
 147 |     if tools.is_empty() {
 148 |         return response;
 149 |     }
 150 | 
 151 |     let mut rewritten = Vec::with_capacity(response.message.content.len());
 152 |     let mut parsed_calls: Vec<(String, String)> = Vec::new();
 153 |     let allowed_tools: std::collections::HashSet<&str> =
 154 |         tools.iter().map(|t| t.name.as_str()).collect();
 155 | 
 156 |     for part in response.message.content {
 157 |         match part {
 158 |             ContentPart::Text { text } => {
 159 |                 let (cleaned, calls) = extract_markup_tool_calls(&text);
 160 |                 for (name, arguments) in calls {
 161 |                     if allowed_tools.contains(name.as_str()) {
 162 |                         parsed_calls.push((name, arguments));
 163 |                     } else {
 164 |                         tracing::warn!(tool = %name, "Ignoring unknown <tool_call> tool name");
 165 |                     }
 166 |                 }
 167 | 
 168 |                 if !cleaned.trim().is_empty() {
 169 |                     rewritten.push(ContentPart::Text {
 170 |                         text: cleaned.trim().to_string(),
 171 |                     });
 172 |                 }
 173 |             }
 174 |             other => rewritten.push(other),
 175 |         }
 176 |     }
 177 | 
 178 |     if parsed_calls.is_empty() {
 179 |         response.message.content = rewritten;
 180 |         return response;
 181 |     }
 182 | 
 183 |     for (name, arguments) in parsed_calls {
 184 |         rewritten.push(ContentPart::ToolCall {
 185 |             id: Uuid::new_v4().to_string(),
 186 |             name,
 187 |             arguments,
 188 |             thought_signature: None,
 189 |         });
 190 |     }
 191 | 
 192 |     response.message.content = rewritten;
 193 |     response.finish_reason = FinishReason::ToolCalls;
 194 |     response
 195 | }
