 295 | fn build_request_requires_tool(session_messages: &[Message], workspace_dir: &Path) -> bool {
 296 |     let Some(text) = latest_user_text(session_messages) else {
 297 |         return false;
 298 |     };
 299 | 
 300 |     if looks_like_build_execution_request(&text)
 301 |         && !extract_candidate_file_paths(&text, workspace_dir, 1).is_empty()
 302 |     {
 303 |         return true;
 304 |     }
 305 | 
 306 |     if !is_affirmative_build_followup(&text) {
 307 |         return false;
 308 |     }
 309 | 
 310 |     let mut skipped_latest_user = false;
 311 |     for msg in session_messages.iter().rev() {
 312 |         let msg_text = extract_text_content(&msg.content);
 313 |         if msg_text.trim().is_empty() {
 314 |             continue;
 315 |         }
 316 | 
 317 |         if matches!(msg.role, Role::User) && !skipped_latest_user {
 318 |             skipped_latest_user = true;
 319 |             continue;
 320 |         }
 321 | 
 322 |         if matches!(msg.role, Role::Assistant) && assistant_offered_next_step(&msg_text) {
 323 |             return true;
 324 |         }
 325 | 
 326 |         if (looks_like_build_execution_request(&msg_text) || looks_like_proposed_change(&msg_text))
 327 |             && !extract_candidate_file_paths(&msg_text, workspace_dir, 1).is_empty()
 328 |         {
 329 |             return true;
 330 |         }
 331 |     }
 332 | 
 333 |     false
 334 | }
