 541 | fn estimate_tokens_for_part(part: &ContentPart) -> usize {
 542 |     match part {
 543 |         ContentPart::Text { text } => RlmChunker::estimate_tokens(text),
 544 |         ContentPart::ToolResult { content, .. } => RlmChunker::estimate_tokens(content),
 545 |         ContentPart::ToolCall {
 546 |             id,
 547 |             name,
 548 |             arguments,
 549 |             thought_signature,
 550 |             ..
 551 |         } => {
 552 |             let mut s = String::new();
 553 |             s.push_str(id);
 554 |             s.push(' ');
 555 |             s.push_str(name);
 556 |             s.push(' ');
 557 |             s.push_str(arguments);
 558 |             if let Some(sig) = thought_signature {
 559 |                 s.push(' ');
 560 |                 s.push_str(sig);
 561 |             }
 562 |             RlmChunker::estimate_tokens(&s)
 563 |         }
 564 |         ContentPart::Thinking { text } => RlmChunker::estimate_tokens(text),
 565 |         ContentPart::Image { .. } => {
 566 |             // Image parts are encoded/handled provider-side and do not map
 567 |             // cleanly to text tokens. Use a conservative fixed estimate.
 568 |             2000
 569 |         }
 570 |         ContentPart::File { path, mime_type } => {
 571 |             let mut s = String::new();
 572 |             s.push_str(path);
 573 |             if let Some(mt) = mime_type {
 574 |                 s.push(' ');
 575 |                 s.push_str(mt);
 576 |             }
 577 |             RlmChunker::estimate_tokens(&s)
 578 |         }
 579 |     }
 580 | }
