 584 |         .iter()
 585 |         .map(|m| {
 586 |             m.content
 587 |                 .iter()
 588 |                 .map(estimate_tokens_for_part)
 589 |                 .sum::<usize>()
 590 |         })
 591 |         .sum()
 592 | }
