 594 | fn estimate_tokens_for_tools(tools: &[ToolDefinition]) -> usize {
 595 |     // Tool definitions are serialized and sent to providers. Count them as part
 596 |     // of the prompt budget to avoid unexpected overflows.
 597 |     serde_json::to_string(tools)
 598 |         .ok()
 599 |         .map(|s| RlmChunker::estimate_tokens(&s))
 600 |         .unwrap_or(0)
 601 | }
