 603 | fn estimate_request_tokens(
 604 |     system_prompt: &str,
 605 |     messages: &[Message],
 606 |     tools: &[ToolDefinition],
 607 | ) -> usize {
 608 |     RlmChunker::estimate_tokens(system_prompt)
 609 |         + estimate_tokens_for_messages(messages)
 610 |         + estimate_tokens_for_tools(tools)
