 677 | fn list_tools_bootstrap_output(tools: &[ToolDefinition], tool_input: &Value) -> String {
 678 |     let requested_tool = tool_input
 679 |         .get("tool")
 680 |         .and_then(Value::as_str)
 681 |         .map(str::trim)
 682 |         .filter(|s| !s.is_empty());
 683 | 
 684 |     if let Some(name) = requested_tool {
 685 |         if let Some(found) = tools.iter().find(|t| t.name.eq_ignore_ascii_case(name)) {
 686 |             return serde_json::to_string_pretty(&json!({
 687 |                 "mode": "tool",
 688 |                 "tool": {
 689 |                     "name": found.name,
 690 |                     "description": found.description,
 691 |                     "parameters": found.parameters
 692 |                 }
 693 |             }))
 694 |             .unwrap_or_else(|_| format!("tool: {}", found.name));
 695 |         }
 696 |         return serde_json::to_string_pretty(&json!({
 697 |             "mode": "tool",
 698 |             "error": format!("Tool '{}' not found", name)
 699 |         }))
 700 |         .unwrap_or_else(|_| format!("Tool '{}' not found", name));
 701 |     }
 702 | 
 703 |     let query = tool_input
 704 |         .get("query")
 705 |         .and_then(Value::as_str)
 706 |         .map(str::trim)
 707 |         .filter(|s| !s.is_empty())
 708 |         .map(|s| s.to_ascii_lowercase());
 709 | 
 710 |     let mut listed: Vec<Value> = tools
 711 |         .iter()
 712 |         .filter(|t| {
 713 |             if let Some(q) = &query {
 714 |                 t.name.to_ascii_lowercase().contains(q)
 715 |                     || t.description.to_ascii_lowercase().contains(q)
 716 |             } else {
 717 |                 true
 718 |             }
 719 |         })
 720 |         .map(|t| {
 721 |             json!({
 722 |                 "name": t.name,
 723 |                 "description": t.description,
 724 |             })
 725 |         })
 726 |         .collect();
 727 | 
 728 |     listed.sort_by(|a, b| {
 729 |         let an = a["name"].as_str().unwrap_or_default();
 730 |         let bn = b["name"].as_str().unwrap_or_default();
 731 |         an.cmp(bn)
 732 |     });
 733 | 
 734 |     serde_json::to_string_pretty(&json!({
 735 |         "mode": "list",
 736 |         "count": listed.len(),
 737 |         "tools": listed,
 738 |         "hint": "Call list_tools with {\"tool\":\"<name>\"} to fetch full parameter schema for one tool."
 739 |     }))
 740 |     .unwrap_or_else(|_| "{\"mode\":\"list\",\"error\":\"serialization_failed\"}".to_string())
 741 | }
