 763 | fn detect_stub_in_tool_input(tool_name: &str, tool_input: &Value) -> Option<String> {
 764 |     let check = |label: &str, text: &str| {
 765 |         stub_marker_in_text(text).map(|marker| format!("{label} contains stub marker \"{marker}\""))
 766 |     };
 767 | 
 768 |     match tool_name {
 769 |         "write" => tool_input
 770 |             .get("content")
 771 |             .and_then(Value::as_str)
 772 |             .and_then(|text| check("content", text)),
 773 |         "edit" | "confirm_edit" => tool_input
 774 |             .get("new_string")
 775 |             .or_else(|| tool_input.get("newString"))
 776 |             .and_then(Value::as_str)
 777 |             .and_then(|text| check("new_string", text)),
 778 |         "advanced_edit" => tool_input
 779 |             .get("newString")
 780 |             .and_then(Value::as_str)
 781 |             .and_then(|text| check("newString", text)),
 782 |         "multiedit" | "confirm_multiedit" => {
 783 |             let edits = tool_input.get("edits").and_then(Value::as_array)?;
 784 |             for (idx, edit) in edits.iter().enumerate() {
 785 |                 if let Some(reason) = edit
 786 |                     .get("new_string")
 787 |                     .or_else(|| edit.get("newString"))
 788 |                     .and_then(Value::as_str)
 789 |                     .and_then(|text| check(&format!("edits[{idx}].new_string"), text))
 790 |                 {
 791 |                     return Some(reason);
 792 |                 }
 793 |             }
 794 |             None
 795 |         }
 796 |         "patch" => {
 797 |             let patch = tool_input.get("patch").and_then(Value::as_str)?;
 798 |             let added_lines = patch
 799 |                 .lines()
 800 |                 .filter(|line| line.starts_with('+') && !line.starts_with("+++"))
 801 |                 .map(|line| line.trim_start_matches('+'))
 802 |                 .collect::<Vec<_>>()
 803 |                 .join("\n");
 804 |             if added_lines.is_empty() {
 805 |                 None
 806 |             } else {
 807 |                 check("patch additions", &added_lines)
 808 |             }
 809 |         }
 810 |         _ => None,
 811 |     }
 812 | }
