 814 | fn normalize_tool_call_for_execution(tool_name: &str, tool_input: &Value) -> (String, Value) {
 815 |     let mut normalized_name = tool_name.to_string();
 816 |     let mut normalized_input = tool_input.clone();
 817 | 
 818 |     if tool_name == "advanced_edit" {
 819 |         normalized_name = "edit".to_string();
 820 |     }
 821 | 
 822 |     if matches!(
 823 |         normalized_name.as_str(),
 824 |         "edit" | "confirm_edit" | "advanced_edit"
 825 |     ) {
 826 |         if let Some(obj) = normalized_input.as_object_mut() {
 827 |             if obj.get("path").is_none() {
 828 |                 if let Some(v) = obj.get("filePath").cloned() {
 829 |                     obj.insert("path".to_string(), v);
 830 |                 } else if let Some(v) = obj.get("file").cloned() {
 831 |                     obj.insert("path".to_string(), v);
 832 |                 }
 833 |             }
 834 |             if obj.get("old_string").is_none()
 835 |                 && let Some(v) = obj.get("oldString").cloned()
 836 |             {
 837 |                 obj.insert("old_string".to_string(), v);
 838 |             }
 839 |             if obj.get("new_string").is_none()
 840 |                 && let Some(v) = obj.get("newString").cloned()
 841 |             {
 842 |                 obj.insert("new_string".to_string(), v);
 843 |             }
 844 |         }
 845 |     }
 846 | 
 847 |     if matches!(normalized_name.as_str(), "multiedit" | "confirm_multiedit")
 848 |         && let Some(obj) = normalized_input.as_object_mut()
 849 |     {
 850 |         if obj.get("edits").is_none() {
 851 |             if let Some(v) = obj.get("changes").cloned() {
 852 |                 obj.insert("edits".to_string(), v);
 853 |             } else if let Some(v) = obj.get("operations").cloned() {
 854 |                 obj.insert("edits".to_string(), v);
 855 |             } else if obj.get("file").is_some() || obj.get("path").is_some() {
 856 |                 let single = Value::Object(obj.clone());
 857 |                 obj.insert("edits".to_string(), Value::Array(vec![single]));
 858 |             }
 859 |         }
 860 | 
 861 |         if let Some(edits) = obj.get_mut("edits").and_then(Value::as_array_mut) {
 862 |             for edit in edits {
 863 |                 if let Some(edit_obj) = edit.as_object_mut() {
 864 |                     if edit_obj.get("file").is_none() {
 865 |                         if let Some(v) = edit_obj.get("filePath").cloned() {
 866 |                             edit_obj.insert("file".to_string(), v);
 867 |                         } else if let Some(v) = edit_obj.get("path").cloned() {
 868 |                             edit_obj.insert("file".to_string(), v);
 869 |                         }
 870 |                     }
 871 |                     if edit_obj.get("old_string").is_none()
 872 |                         && let Some(v) = edit_obj.get("oldString").cloned()
 873 |                     {
 874 |                         edit_obj.insert("old_string".to_string(), v);
 875 |                     }
 876 |                     if edit_obj.get("new_string").is_none()
 877 |                         && let Some(v) = edit_obj.get("newString").cloned()
 878 |                     {
 879 |                         edit_obj.insert("new_string".to_string(), v);
 880 |                     }
 881 |                 }
 882 |             }
 883 |         }
 884 |     }
 885 | 
 886 |     (normalized_name, normalized_input)
 887 | }
