 889 | fn latest_user_text(messages: &[Message]) -> Option<String> {
 890 |     messages.iter().rev().find_map(|m| {
 891 |         if m.role != Role::User {
 892 |             return None;
 893 |         }
 894 |         let text = m
 895 |             .content
 896 |             .iter()
 897 |             .filter_map(|part| match part {
 898 |                 ContentPart::Text { text } => Some(text.as_str()),
 899 |                 _ => None,
 900 |             })
 901 |             .collect::<Vec<_>>()
 902 |             .join("\n");
 903 |         if text.trim().is_empty() {
 904 |             None
 905 |         } else {
 906 |             Some(text)
 907 |         }
 908 |     })
 909 | }
