 911 | fn extract_candidate_file_paths(text: &str, cwd: &Path, max_files: usize) -> Vec<String> {
 912 |     static FILE_PATH_RE: OnceLock<Regex> = OnceLock::new();
 913 |     let re = FILE_PATH_RE.get_or_init(|| {
 914 |         Regex::new(
 915 |             r"(?x)
 916 |             (?P<path>
 917 |               (?:\.?/)?(?:[A-Za-z0-9_.\-]+/)*
 918 |               [A-Za-z0-9_.\-]+\.
 919 |               (?:rs|ts|tsx|js|jsx|mjs|cjs|py|go|java|kt|swift|c|cc|cpp|h|hpp|cs|php|rb|scala|sql|json|ya?ml|toml)
 920 |             )",
 921 |         )
 922 |         .unwrap()
 923 |     });
 924 | 
 925 |     let mut out = Vec::new();
 926 |     for cap in re.captures_iter(text) {
 927 |         let Some(raw) = cap.name("path").map(|m| m.as_str()) else {
 928 |             continue;
 929 |         };
 930 |         let path = raw
 931 |             .trim_matches(|c: char| {
 932 |                 matches!(
 933 |                     c,
 934 |                     '`' | '"' | '\'' | '(' | ')' | '[' | ']' | '{' | '}' | ',' | ';' | ':'
 935 |                 )
 936 |             })
 937 |             .to_string();
 938 |         if path.is_empty() || out.iter().any(|p| p == &path) {
 939 |             continue;
 940 |         }
 941 |         if cwd.join(&path).exists() {
 942 |             out.push(path);
 943 |         }
 944 |         if out.len() >= max_files {
 945 |             break;
 946 |         }
 947 |     }
 948 |     out
 949 | }
