 951 | async fn build_proactive_lsp_context_message(
 952 |     selected_provider: &str,
 953 |     step: usize,
 954 |     tool_registry: &ToolRegistry,
 955 |     session_messages: &[Message],
 956 |     workspace_dir: &Path,
 957 | ) -> Option<Message> {
 958 |     // Keep this narrowly scoped to Gemini Web where the user requested
 959 |     // proactive LSP context before tool-calling decisions.
 960 |     if selected_provider != "gemini-web" || step != 1 {
 961 |         return None;
 962 |     }
 963 | 
 964 |     let Some(lsp_tool) = tool_registry.get("lsp") else {
 965 |         return None;
 966 |     };
 967 | 
 968 |     let Some(user_text) = latest_user_text(session_messages) else {
 969 |         return None;
 970 |     };
 971 | 
 972 |     let max_files = std::env::var("CODETETHER_PROACTIVE_LSP_MAX_FILES")
 973 |         .ok()
 974 |         .and_then(|v| v.parse::<usize>().ok())
 975 |         .filter(|v| *v > 0)
 976 |         .unwrap_or(1);
 977 | 
 978 |     let max_chars = std::env::var("CODETETHER_PROACTIVE_LSP_MAX_CHARS")
 979 |         .ok()
 980 |         .and_then(|v| v.parse::<usize>().ok())
 981 |         .filter(|v| *v > 0)
 982 |         .unwrap_or(600);
 983 | 
 984 |     let paths = extract_candidate_file_paths(&user_text, workspace_dir, max_files);
 985 |     if paths.is_empty() {
 986 |         return None;
 987 |     }
 988 | 
 989 |     let mut sections: Vec<String> = Vec::new();
 990 |     for path in paths {
 991 |         let args = json!({
 992 |             "action": "documentSymbol",
 993 |             "file_path": path,
 994 |             "line": 1,
 995 |             "column": 1
 996 |         });
 997 | 
 998 |         match lsp_tool.execute(args).await {
 999 |             Ok(result) if result.success => {
1000 |                 sections.push(format!(
1001 |                     "File: {}\n{}",
1002 |                     path,
1003 |                     truncate_with_ellipsis(&result.output, max_chars)
1004 |                 ));
1005 |             }
1006 |             Ok(result) => {
1007 |                 tracing::debug!(
1008 |                     file = %path,
1009 |                     output = %truncate_with_ellipsis(&result.output, 200),
1010 |                     "Proactive LSP context skipped file due to unsuccessful result"
1011 |                 );
1012 |             }
1013 |             Err(e) => {
1014 |                 tracing::debug!(file = %path, error = %e, "Proactive LSP prefetch failed");
1015 |             }
1016 |         }
1017 |     }
1018 | 
1019 |     if sections.is_empty() {
1020 |         return None;
1021 |     }
1022 | 
1023 |     Some(Message {
1024 |         role: Role::System,
1025 |         content: vec![ContentPart::Text {
1026 |             text: format!(
1027 |                 "Proactive LSP context (prefetched). Use this to reason about file structure before issuing more tools.\n\n{}",
1028 |                 sections.join("\n\n---\n\n")
1029 |             ),
1030 |         }],
1031 |     })
1032 | }
