1034 | fn messages_to_rlm_context(messages: &[Message]) -> String {
1035 |     // Render a lossless-ish text representation of the session suitable for RLM.
1036 |     // Avoid embedding base64 image data URLs (they can be enormous and not useful
1037 |     // for summarizing conversational state).
1038 |     let mut out = String::new();
1039 |     for (idx, m) in messages.iter().enumerate() {
1040 |         out.push_str(&format!("[{} {}]\n", idx, role_label(m.role)));
1041 | 
1042 |         for part in &m.content {
1043 |             match part {
1044 |                 ContentPart::Text { text } => {
1045 |                     out.push_str(text);
1046 |                     out.push('\n');
1047 |                 }
1048 |                 ContentPart::Thinking { text } => {
1049 |                     if !text.trim().is_empty() {
1050 |                         out.push_str("[Thinking]\n");
1051 |                         out.push_str(text);
1052 |                         out.push('\n');
1053 |                     }
1054 |                 }
1055 |                 ContentPart::ToolCall {
1056 |                     id,
1057 |                     name,
1058 |                     arguments,
1059 |                     ..
1060 |                 } => {
1061 |                     out.push_str(&format!(
1062 |                         "[ToolCall id={id} name={name}]\nargs: {arguments}\n"
1063 |                     ));
1064 |                 }
1065 |                 ContentPart::ToolResult {
1066 |                     tool_call_id,
1067 |                     content,
1068 |                 } => {
1069 |                     out.push_str(&format!("[ToolResult id={tool_call_id}]\n"));
1070 |                     out.push_str(content);
1071 |                     out.push('\n');
1072 |                 }
1073 |                 ContentPart::Image { mime_type, url } => {
1074 |                     out.push_str(&format!(
1075 |                         "[Image mime_type={} url_len={}]\n",
1076 |                         mime_type.clone().unwrap_or_else(|| "unknown".to_string()),
1077 |                         url.len()
1078 |                     ));
1079 |                 }
1080 |                 ContentPart::File { path, mime_type } => {
1081 |                     out.push_str(&format!(
1082 |                         "[File path={} mime_type={}]\n",
1083 |                         path,
1084 |                         mime_type.clone().unwrap_or_else(|| "unknown".to_string())
1085 |                     ));
1086 |                 }
1087 |             }
1088 |         }
1089 | 
1090 |         out.push_str("\n---\n\n");
1091 |     }
1092 |     out
1093 | }
