1159 | 
1160 |     for candidate in known_good_router_candidates(selected_provider, current_model) {
1161 |         let (provider_name, model_name) = crate::provider::parse_model_string(&candidate);
1162 |         let provider_name = provider_name.unwrap_or(selected_provider);
1163 |         if registry.get(provider_name).is_some() {
1164 |             return Some((provider_name.to_string(), model_name.to_string()));
