1265 |     /// Load the last session, optionally scoped to a workspace directory
1266 |     ///
1267 |     /// When `workspace` is Some, only considers sessions created in that directory.
1268 |     /// When None, returns the most recent session globally (legacy behavior).
1269 |     pub async fn last_for_directory(workspace: Option<&std::path::Path>) -> Result<Self> {
1270 |         let sessions_dir = Self::sessions_dir()?;
1271 | 
1272 |         if !sessions_dir.exists() {
1273 |             anyhow::bail!("No sessions found");
1274 |         }
1275 | 
1276 |         let mut entries: Vec<tokio::fs::DirEntry> = Vec::new();
1277 |         let mut read_dir = fs::read_dir(&sessions_dir).await?;
1278 |         while let Some(entry) = read_dir.next_entry().await? {
1279 |             entries.push(entry);
1280 |         }
1281 | 
1282 |         if entries.is_empty() {
1283 |             anyhow::bail!("No sessions found");
1284 |         }
1285 | 
1286 |         // Sort by modification time (most recent first)
1287 |         // Use std::fs::metadata since we can't await in sort_by_key
1288 |         entries.sort_by_key(|e| {
1289 |             std::cmp::Reverse(
1290 |                 std::fs::metadata(e.path())
1291 |                     .ok()
1292 |                     .and_then(|m| m.modified().ok())
1293 |                     .unwrap_or(std::time::SystemTime::UNIX_EPOCH),
1294 |             )
1295 |         });
1296 | 
1297 |         let canonical_workspace =
1298 |             workspace.map(|w| w.canonicalize().unwrap_or_else(|_| w.to_path_buf()));
1299 | 
1300 |         for entry in &entries {
1301 |             let content: String = fs::read_to_string(entry.path()).await?;
1302 |             if let Ok(session) = serde_json::from_str::<Session>(&content) {
1303 |                 // If workspace scoping requested, filter by directory
1304 |                 if let Some(ref ws) = canonical_workspace {
1305 |                     if let Some(ref dir) = session.metadata.directory {
1306 |                         let canonical_dir = dir.canonicalize().unwrap_or_else(|_| dir.clone());
1307 |                         if &canonical_dir == ws {
1308 |                             return Ok(session);
1309 |                         }
1310 |                     }
1311 |                     continue;
1312 |                 }
1313 |                 return Ok(session);
1314 |             }
1315 |         }
1316 | 
1317 |         anyhow::bail!("No sessions found")
1318 |     }
