1345 |     async fn compress_history_keep_last(
1346 |         &mut self,
1347 |         provider: Arc<dyn crate::provider::Provider>,
1348 |         model: &str,
1349 |         keep_last: usize,
1350 |         reason: &str,
1351 |     ) -> Result<bool> {
1352 |         if self.messages.len() <= keep_last {
1353 |             return Ok(false);
1354 |         }
1355 | 
1356 |         let split_idx = self.messages.len().saturating_sub(keep_last);
1357 |         let tail = self.messages.split_off(split_idx);
1358 |         let prefix = std::mem::take(&mut self.messages);
1359 | 
1360 |         let context = messages_to_rlm_context(&prefix);
1361 |         let ctx_window = context_window_for_model(model);
1362 | 
1363 |         // We call auto_process directly for session context. It internally
1364 |         // compresses very large inputs before hitting the model.
1365 |         let rlm_config = RlmConfig::default();
1366 |         let auto_ctx = AutoProcessContext {
1367 |             tool_id: "session_context",
1368 |             tool_args: serde_json::json!({"reason": reason}),
1369 |             session_id: &self.id,
1370 |             abort: None,
1371 |             on_progress: None,
1372 |             provider,
1373 |             model: model.to_string(),
1374 |         };
1375 | 
1376 |         let summary = match RlmRouter::auto_process(&context, auto_ctx, &rlm_config).await {
1377 |             Ok(result) => {
1378 |                 tracing::info!(
1379 |                     reason,
1380 |                     input_tokens = result.stats.input_tokens,
1381 |                     output_tokens = result.stats.output_tokens,
1382 |                     compression_ratio = result.stats.compression_ratio,
1383 |                     "RLM: Compressed session history"
1384 |                 );
1385 |                 result.processed
1386 |             }
1387 |             Err(e) => {
1388 |                 tracing::warn!(reason, error = %e, "RLM: Failed to compress session history; falling back to chunk compression");
1389 |                 // Fallback: keep a smaller, semantically chunked excerpt.
1390 |                 RlmChunker::compress(&context, (ctx_window as f64 * 0.25) as usize, None)
1391 |             }
1392 |         };
1393 | 
1394 |         let summary_msg = Message {
1395 |             role: Role::Assistant,
1396 |             content: vec![ContentPart::Text {
1397 |                 text: format!(
1398 |                     "[AUTO CONTEXT COMPRESSION]\nOlder conversation + tool output was compressed to fit the model context window.\n\n{}",
1399 |                     summary
1400 |                 ),
1401 |             }],
1402 |         };
1403 | 
1404 |         let mut new_messages = Vec::with_capacity(1 + tail.len());
1405 |         new_messages.push(summary_msg);
1406 |         new_messages.extend(tail);
1407 |         self.messages = new_messages;
1408 |         self.updated_at = Utc::now();
1409 | 
1410 |         Ok(true)
1411 |     }
