1413 |     async fn enforce_context_window(
1414 |         &mut self,
1415 |         provider: Arc<dyn crate::provider::Provider>,
1416 |         model: &str,
1417 |         system_prompt: &str,
1418 |         tools: &[ToolDefinition],
1419 |     ) -> Result<()> {
1420 |         let ctx_window = context_window_for_model(model);
1421 | 
1422 |         // Reserve response tokens + a small fixed overhead for tool schemas,
1423 |         // protocol framing, and provider-specific wrappers.
1424 |         let reserve = session_completion_max_tokens().saturating_add(2048);
1425 |         let budget = ctx_window.saturating_sub(reserve);
1426 |         let safety_budget = (budget as f64 * 0.90) as usize;
1427 | 
1428 |         // Try progressively more aggressive compression.
1429 |         let keep_last_candidates = [16usize, 12, 8, 6];
1430 |         for keep_last in keep_last_candidates {
1431 |             let est = estimate_request_tokens(system_prompt, &self.messages, tools);
1432 |             if est <= safety_budget {
1433 |                 return Ok(());
1434 |             }
1435 | 
1436 |             tracing::info!(
1437 |                 est_tokens = est,
1438 |                 ctx_window,
1439 |                 safety_budget,
1440 |                 keep_last,
1441 |                 "Context window approaching limit; compressing older session history"
1442 |             );
1443 | 
1444 |             let did = self
1445 |                 .compress_history_keep_last(
1446 |                     Arc::clone(&provider),
1447 |                     model,
1448 |                     keep_last,
1449 |                     "context_budget",
1450 |                 )
1451 |                 .await?;
1452 | 
1453 |             if !did {
1454 |                 // Nothing left to compress.
1455 |                 break;
1456 |             }
1457 |         }
1458 | 
1459 |         Ok(())
1460 |     }
