1462 |     /// Execute a prompt and get the result
1463 |     pub async fn prompt(&mut self, message: &str) -> Result<SessionResult> {
1464 |         use crate::provider::{
1465 |             CompletionRequest, ContentPart, ProviderRegistry, Role, parse_model_string,
1466 |         };
1467 | 
1468 |         // Load providers from Vault
1469 |         let registry = ProviderRegistry::from_vault().await?;
1470 | 
1471 |         let providers = registry.list();
1472 |         if providers.is_empty() {
1473 |             anyhow::bail!(
1474 |                 "No providers available. Configure provider credentials in HashiCorp Vault (for ChatGPT subscription Codex use `codetether auth codex`; for Copilot use `codetether auth copilot`)."
1475 |             );
1476 |         }
1477 | 
1478 |         tracing::info!("Available providers: {:?}", providers);
1479 | 
1480 |         // Parse model string (format: "provider/model", "provider", or just "model")
1481 |         let (provider_name, model_id) = if let Some(ref model_str) = self.metadata.model {
1482 |             let (prov, model) = parse_model_string(model_str);
1483 |             let prov = prov.map(|p| if p == "zhipuai" { "zai" } else { p });
1484 |             if prov.is_some() {
1485 |                 // Format: provider/model
1486 |                 (prov.map(|s| s.to_string()), model.to_string())
1487 |             } else if providers.contains(&model) {
1488 |                 // Format: just provider name (e.g., "novita")
1489 |                 (Some(model.to_string()), String::new())
1490 |             } else {
1491 |                 // Format: just model name
1492 |                 (None, model.to_string())
1493 |             }
1494 |         } else {
1495 |             (None, String::new())
1496 |         };
1497 | 
1498 |         let selected_provider =
1499 |             resolve_provider_for_session_request(providers.as_slice(), provider_name.as_deref())?;
1500 | 
1501 |         let provider = registry
1502 |             .get(selected_provider)
1503 |             .ok_or_else(|| anyhow::anyhow!("Provider {} not found", selected_provider))?;
1504 | 
1505 |         // Add user message to session using add_message
1506 |         self.add_message(Message {
1507 |             role: Role::User,
1508 |             content: vec![ContentPart::Text {
1509 |                 text: message.to_string(),
1510 |             }],
1511 |         });
1512 | 
1513 |         // Generate title if this is the first user message and no title exists
1514 |         if self.title.is_none() {
1515 |             self.generate_title().await?;
1516 |         }
1517 | 
1518 |         // Determine model to use
1519 |         let model = if !model_id.is_empty() {
1520 |             model_id
1521 |         } else {
1522 |             Self::default_model_for_provider(selected_provider)
1523 |         };
1524 | 
1525 |         // Compress oversized user message via RLM if it exceeds the context threshold
1526 |         {
1527 |             let ctx_window = context_window_for_model(&model);
1528 |             let msg_tokens = RlmChunker::estimate_tokens(message);
1529 |             let threshold = (ctx_window as f64 * 0.35) as usize;
1530 |             if msg_tokens > threshold {
1531 |                 tracing::info!(
1532 |                     msg_tokens,
1533 |                     threshold,
1534 |                     ctx_window,
1535 |                     "RLM: User message exceeds context threshold, compressing"
1536 |                 );
1537 |                 let auto_ctx = AutoProcessContext {
1538 |                     tool_id: "session_context",
1539 |                     tool_args: serde_json::json!({}),
1540 |                     session_id: &self.id,
1541 |                     abort: None,
1542 |                     on_progress: None,
1543 |                     provider: Arc::clone(&provider),
1544 |                     model: model.clone(),
1545 |                 };
1546 |                 let rlm_config = RlmConfig::default();
1547 |                 match RlmRouter::auto_process(message, auto_ctx, &rlm_config).await {
1548 |                     Ok(result) => {
1549 |                         tracing::info!(
1550 |                             input_tokens = result.stats.input_tokens,
1551 |                             output_tokens = result.stats.output_tokens,
1552 |                             "RLM: User message compressed"
1553 |                         );
1554 |                         // Replace the last message (user message we just added)
1555 |                         if let Some(last) = self.messages.last_mut() {
1556 |                             last.content = vec![ContentPart::Text {
1557 |                                 text: format!(
1558 |                                     "[Original message: {} tokens, compressed via RLM]\n\n{}\n\n---\nOriginal request prefix:\n{}",
1559 |                                     msg_tokens,
1560 |                                     result.processed,
1561 |                                     message.chars().take(500).collect::<String>()
1562 |                                 ),
1563 |                             }];
1564 |                         }
1565 |                     }
1566 |                     Err(e) => {
1567 |                         tracing::warn!(error = %e, "RLM: Failed to compress user message, using truncation");
1568 |                         let max_chars = threshold * 4;
1569 |                         let truncated = RlmChunker::compress(message, max_chars / 4, None);
1570 |                         if let Some(last) = self.messages.last_mut() {
1571 |                             last.content = vec![ContentPart::Text { text: truncated }];
1572 |                         }
1573 |                     }
1574 |                 }
1575 |             }
1576 |         }
1577 | 
1578 |         // Create tool registry with all available tools
1579 |         let tool_registry = ToolRegistry::with_provider_arc(Arc::clone(&provider), model.clone());
1580 |         let tool_definitions: Vec<_> = tool_registry
1581 |             .definitions()
1582 |             .into_iter()
1583 |             .filter(|tool| !is_interactive_tool(&tool.name))
1584 |             .collect();
1585 | 
1586 |         // Some models behave best with temperature=1.0.
1587 |         // - Kimi K2.x requires temperature=1.0
1588 |         // - GLM (Z.AI) defaults to temperature 1.0 for coding workflows
1589 |         // Use contains() to match both short aliases and provider-qualified IDs.
1590 |         let temperature = if prefers_temperature_one(&model) {
1591 |             Some(1.0)
1592 |         } else {
1593 |             Some(0.7)
1594 |         };
1595 | 
1596 |         tracing::info!("Using model: {} via provider: {}", model, selected_provider);
1597 |         tracing::info!("Available tools: {}", tool_definitions.len());
1598 | 
1599 |         // Most providers support native tool calling.  For providers that
1600 |         // don't (e.g. gemini-web), the FunctionGemma tool-call router will
1601 |         // convert text-only responses into structured tool calls.
1602 |         let model_supports_tools = !matches!(
1603 |             selected_provider,
1604 |             "gemini-web" | "local-cuda" | "local_cuda" | "localcuda"
1605 |         );
1606 |         let advertised_tool_definitions = if model_supports_tools {
1607 |             tool_definitions.clone()
1608 |         } else {
1609 |             vec![list_tools_bootstrap_definition()]
1610 |         };
1611 | 
1612 |         // Build system prompt with AGENTS.md
1613 |         let cwd = self
1614 |             .metadata
1615 |             .directory
1616 |             .clone()
1617 |             .unwrap_or_else(|| std::env::current_dir().unwrap_or_default());
1618 |         let system_prompt = if is_local_cuda_provider(selected_provider) {
1619 |             local_cuda_light_system_prompt()
1620 |         } else {
1621 |             crate::agent::builtin::build_system_prompt(&cwd)
1622 |         };
1623 | 
1624 |         // For models that don't support native tool calling, inject tool
1625 |         // definitions into the system prompt so the model outputs <tool_call>
1626 |         // XML blocks that the router can parse directly.
1627 |         let system_prompt = if !model_supports_tools && !advertised_tool_definitions.is_empty() {
1628 |             inject_tool_prompt(&system_prompt, &advertised_tool_definitions)
1629 |         } else {
1630 |             system_prompt
1631 |         };
1632 | 
1633 |         // Run agentic loop with tool execution
1634 |         let max_steps = 50;
1635 |         let mut final_output = String::new();
1636 | 
1637 |         // Track consecutive identical tool calls to detect infinite loops.
1638 |         let mut last_tool_sig: Option<String> = None;
1639 |         let mut consecutive_same_tool: u32 = 0;
1640 |         let mut consecutive_codesearch_no_matches: u32 = 0;
1641 |         let mut build_mode_tool_retry_count: u8 = 0;
1642 |         let mut native_tool_promise_retry_count: u8 = 0;
1643 |         const MAX_CONSECUTIVE_SAME_TOOL: u32 = 3;
1644 | 
1645 |         // Initialise the FunctionGemma tool-call router (feature-gated, opt-in).
1646 | 
1647 |         let tool_router: Option<ToolCallRouter> = {
1648 |             let cfg = ToolRouterConfig::from_env();
1649 |             match ToolCallRouter::from_config(&cfg) {
1650 |                 Ok(r) => r,
1651 |                 Err(e) => {
1652 |                     tracing::warn!(error = %e, "FunctionGemma tool router init failed; disabled");
1653 |                     None
1654 |                 }
1655 |             }
1656 |         };
1657 | 
1658 |         for step in 1..=max_steps {
1659 |             tracing::info!(step = step, "Agent step starting");
1660 | 
1661 |             // Proactively keep the prompt within the model's context window.
1662 |             self.enforce_context_window(
1663 |                 Arc::clone(&provider),
1664 |                 &model,
1665 |                 &system_prompt,
1666 |                 &advertised_tool_definitions,
1667 |             )
1668 |             .await?;
1669 | 
1670 |             let proactive_lsp_message = build_proactive_lsp_context_message(
1671 |                 selected_provider,
1672 |                 step,
1673 |                 &tool_registry,
1674 |                 &self.messages,
1675 |                 &cwd,
1676 |             )
1677 |             .await;
1678 | 
1679 |             // Call the provider (retry once if the provider rejects due to an
1680 |             // unexpected context-length mismatch).
1681 |             let mut attempt = 0;
1682 |             let response = loop {
1683 |                 attempt += 1;
1684 | 
1685 |                 // Build messages with system prompt first
1686 |                 let mut messages = vec![Message {
1687 |                     role: Role::System,
1688 |                     content: vec![ContentPart::Text {
1689 |                         text: system_prompt.clone(),
1690 |                     }],
1691 |                 }];
1692 |                 if let Some(msg) = &proactive_lsp_message {
1693 |                     messages.push(msg.clone());
1694 |                 }
1695 |                 messages.extend(self.messages.clone());
1696 | 
1697 |                 // Create completion request with tools
1698 |                 let request = CompletionRequest {
1699 |                     messages,
1700 |                     tools: advertised_tool_definitions.clone(),
1701 |                     model: model.clone(),
1702 |                     temperature,
1703 |                     top_p: None,
1704 |                     max_tokens: Some(session_completion_max_tokens()),
1705 |                     stop: Vec::new(),
1706 |                 };
1707 | 
1708 |                 match provider.complete(request).await {
1709 |                     Ok(r) => break r,
1710 |                     Err(e) => {
1711 |                         if attempt == 1 && is_prompt_too_long_error(&e) {
1712 |                             tracing::warn!(error = %e, "Provider rejected prompt as too long; forcing extra compression and retrying");
1713 |                             let _ = self
1714 |                                 .compress_history_keep_last(
1715 |                                     Arc::clone(&provider),
1716 |                                     &model,
1717 |                                     6,
1718 |                                     "prompt_too_long_retry",
1719 |                                 )
1720 |                                 .await?;
1721 |                             continue;
1722 |                         }
1723 |                         return Err(e);
1724 |                     }
1725 |                 }
1726 |             };
1727 | 
1728 |             // Optionally route text-only responses through FunctionGemma to
1729 |             // produce structured tool calls.  Skipped when the model natively
1730 |             // supports tool calling (which all current providers do).
1731 | 
1732 |             let response = if let Some(ref router) = tool_router {
1733 |                 router
1734 |                     .maybe_reformat(response, &tool_definitions, model_supports_tools)
1735 |                     .await
1736 |             } else {
1737 |                 response
1738 |             };
1739 |             let response = normalize_textual_tool_calls(response, &tool_definitions);
1740 | 
1741 |             // Record token usage
1742 |             crate::telemetry::TOKEN_USAGE.record_model_usage(
1743 |                 &model,
1744 |                 response.usage.prompt_tokens as u64,
1745 |                 response.usage.completion_tokens as u64,
1746 |             );
1747 | 
1748 |             // Extract tool calls from response
1749 |             let tool_calls: Vec<(String, String, serde_json::Value)> = response
1750 |                 .message
1751 |                 .content
1752 |                 .iter()
1753 |                 .filter_map(|part| {
1754 |                     if let ContentPart::ToolCall {
1755 |                         id,
1756 |                         name,
1757 |                         arguments,
1758 |                         ..
1759 |                     } = part
1760 |                     {
1761 |                         // Parse arguments JSON string into Value
1762 |                         let args: serde_json::Value =
1763 |                             serde_json::from_str(arguments).unwrap_or(serde_json::json!({}));
1764 |                         Some((id.clone(), name.clone(), args))
1765 |                     } else {
1766 |                         None
1767 |                     }
1768 |                 })
1769 |                 .collect();
1770 | 
1771 |             let assistant_text = extract_text_content(&response.message.content);
1772 |             if should_force_build_tool_first_retry(
1773 |                 &self.agent,
1774 |                 build_mode_tool_retry_count,
1775 |                 &tool_definitions,
1776 |                 &self.messages,
1777 |                 &cwd,
1778 |                 &assistant_text,
1779 |                 !tool_calls.is_empty(),
1780 |             ) {
1781 |                 build_mode_tool_retry_count += 1;
1782 |                 tracing::warn!(
1783 |                     step = step,
1784 |                     agent = %self.agent,
1785 |                     retry = build_mode_tool_retry_count,
1786 |                     "Build mode tool-first guard triggered; retrying with execution nudge"
1787 |                 );
1788 |                 self.add_message(Message {
1789 |                     role: Role::User,
1790 |                     content: vec![ContentPart::Text {
1791 |                         text: BUILD_MODE_TOOL_FIRST_NUDGE.to_string(),
1792 |                     }],
1793 |                 });
1794 |                 continue;
1795 |             }
1796 |             if should_retry_missing_native_tool_call(
1797 |                 selected_provider,
1798 |                 &model,
1799 |                 native_tool_promise_retry_count,
1800 |                 &tool_definitions,
1801 |                 &assistant_text,
1802 |                 !tool_calls.is_empty(),
1803 |             ) {
1804 |                 native_tool_promise_retry_count += 1;
1805 |                 tracing::warn!(
1806 |                     step = step,
