3396 | fn truncate_with_ellipsis(value: &str, max_chars: usize) -> String {
3397 |     if max_chars == 0 {
3398 |         return String::new();
3399 |     }
3400 | 
3401 |     let mut chars = value.chars();
3402 |     let mut output = String::new();
3403 |     for _ in 0..max_chars {
3404 |         if let Some(ch) = chars.next() {
3405 |             output.push(ch);
3406 |         } else {
3407 |             return value.to_string();
3408 |         }
3409 |     }
3410 | 
3411 |     if chars.next().is_some() {
3412 |         format!("{output}...")
3413 |     } else {
3414 |         output
3415 |     }
3416 | }
